import { Link, useLocation, useNavigate } from 'react-router-dom';

function AdminSidebar() {
  const location = useLocation();
  const navigate = useNavigate();
  const user = JSON.parse(localStorage.getItem('user') || '{}');

  const isActive = (path) => location.pathname === path;

  const menuItems = [
    { path: '/admin', icon: '📊', label: 'Dashboard' },
    { path: '/admin/create-event', icon: '➕', label: 'Create Event' },
    { path: '/admin/manage-events', icon: '📝', label: 'Manage Events' },
    { path: '/admin/bookings', icon: '🎫', label: 'All Bookings' },
    { path: '/admin/payments', icon: '💰', label: 'Payments' },
    { path: '/admin/users', icon: '👥', label: 'Users' },
  ];

  const handleLogout = () => {
    localStorage.removeItem('token');
    localStorage.removeItem('user');
    navigate('/login');
  };

  return (
    <aside className="w-64 min-h-screen bg-gray-900 text-white flex flex-col sticky top-0">

      {/* Header */}
      <div className="p-6 bg-gradient-to-r from-blue-600 to-purple-600">
        <Link to="/admin" className="flex items-center gap-3">
          <span className="text-3xl">🎉</span>
          <div>
            <h2 className="text-lg font-bold">EventHub</h2>
            <p className="text-xs text-blue-200">Admin Panel</p>
          </div>
        </Link>
        <div className="mt-4 flex items-center gap-3">
          <div className="w-9 h-9 bg-white/20 rounded-full flex items-center justify-center text-lg">👤</div>
          <div>
            <p className="text-sm font-semibold">{user.name}</p>
            <p className="text-xs text-blue-200">Administrator</p>
          </div>
        </div>
      </div>

      {/* Navigation */}
      <nav className="flex-1 p-4">
        <p className="text-xs text-gray-500 uppercase tracking-wider mb-3 px-3">Main Menu</p>
        <ul className="space-y-1">
          {menuItems.map((item) => (
            <li key={item.path}>
              <Link
                to={item.path}
                className={`flex items-center gap-3 px-4 py-3 rounded-xl transition-all duration-200 ${
                  isActive(item.path)
                    ? 'bg-gradient-to-r from-blue-500 to-purple-600 text-white shadow-lg'
                    : 'text-gray-400 hover:bg-gray-800 hover:text-white'
                }`}
              >
                <span className="text-xl">{item.icon}</span>
                <span className="font-medium text-sm">{item.label}</span>
                {isActive(item.path) && <span className="ml-auto w-2 h-2 bg-white rounded-full"></span>}
              </Link>
            </li>
          ))}
        </ul>
      </nav>

      {/* Footer */}
      <div className="p-4 border-t border-gray-800 space-y-2">
        <Link to="/home" className="flex items-center gap-3 px-4 py-3 rounded-xl text-gray-400 hover:bg-gray-800 hover:text-white transition text-sm">
          <span>🌐</span> Back to Website
        </Link>
        <button onClick={handleLogout} className="w-full flex items-center gap-3 px-4 py-3 rounded-xl text-red-400 hover:bg-red-900/30 hover:text-red-300 transition text-sm">
          <span>🚪</span> Logout
        </button>
      </div>
    </aside>
  );
}

export default AdminSidebar;
